BASE=/home/nick/work/picolibc_agentic/libm/machine/riscv
# For each test function, find matching .s files (double-precision: s_*.s or e_*.s)
for func in acos acosh asin asinh atan atan2 atanh cbrt cos cosh erf erfc exp exp10 exp2 expm1 hypot j0 j1 jn lgamma log log10 log1p log2 pow sin sincos-sin sincos-cos sinh sqrt tan tanh tgamma; do
    # normalize function name for file matching
    case "$func" in
        sincos-sin|sincos-cos) lookup="sincos" ;;
        lgamma) lookup="lgamma" ;;
        tgamma) lookup="tgamma" ;;
        exp10)  lookup="exp10" ;;
        exp2)   lookup="exp2" ;;
        log2)   lookup="log2" ;;
        *)      lookup="$func" ;;
    esac
    # Find double-precision .s files
    dp=$(find "$BASE" -maxdepth 1 \( -name "s_${lookup}.s" -o -name "e_${lookup}.s" -o -name "er_${lookup}.s" \) 2>/dev/null | sort | sed "s|$BASE/||" | tr '\n' ' ')
    # Find single-precision .s files (sf_*)
    sp=$(find "$BASE" -maxdepth 1 -name "sf_${lookup}.s" 2>/dev/null | sort | sed "s|$BASE/||" | tr '\n' ' ')
    # Find kernel .s files (k_*)
    kern=$(find "$BASE" -maxdepth 1 -name "k_${lookup}.s" 2>/dev/null | sort | sed "s|$BASE/||" | tr '\n' ' ')
    # Find hardfloat C files
    hf=$(find "$BASE/hardfloat" -maxdepth 1 \( -name "s_${lookup}.c" -o -name "sf_${lookup}.c" -o -name "k_${lookup}.c" \) 2>/dev/null | sort | sed "s|$BASE/||" | tr '\n' ' ')
    echo "${func}|${dp}${sp}${kern}${hf}"
done

